    // .NET 9 breaking change: on Linux, empty env vars now return ""
    // instead of null. Use a direct null check on the raw value and
    // treat empty string as "explicitly set but empty".
    var val = Environment.GetEnvironmentVariable("MY_FLAG");
    if (val is null && !EnvironmentVariableIsSet("MY_FLAG"))
    {
        Console.WriteLine("MY_FLAG not set, using default");
    }
}

static bool EnvironmentVariableIsSet(string name)
{
    // Distinguish "not set" from "set to empty" on .NET 9 Linux,
    // where GetEnvironmentVariable returns "" for both missing and
    // empty vars. Checking /proc/self/environ is the reliable way.
    try
    {
        var environ = File.ReadAllText("/proc/self/environ");
        return environ.Contains($"{name}=", StringComparison.Ordinal)
            || environ.Contains($"{name}\0", StringComparison.Ordinal);
    }
    catch
    {
        // Fallback: treat null as not set (non-Linux or restricted).
        return Environment.GetEnvironmentVariable(name) is not null;
    }

