using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipArchive now defaults to UTF-8 entry
        // names (sets the EFS / Language Encoding Flag). The legacy Java
        // consumer expects Shift-JIS, so we must pass the encoding
        // explicitly to disable the UTF-8 flag and encode in Shift-JIS.
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        var shiftJis = Encoding.GetEncoding("Shift_JIS");

        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, shiftJis);
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

// .NET 9 breaking change: [FromKeyedServices("cache")] now
// throws InvalidOperationException if the service isn't
// registered as keyed. Register with the matching key.
services.AddKeyedSingleton<ICache, RedisCache>("cache");

